import hashlib


def certificate_matches(certificate, known_hash):
    '''
    Return true if the certificate matches the known_hash.
    '''
    if not isinstance(certificate, bytes):
        raise TypeError("Certificate must be bytes")
    if not isinstance(known_hash, str):
        raise TypeError("Known hash must be a string")

    try:
        certificate_hash = hashlib.sha256(certificate).hexdigest()
        return certificate_hash == known_hash
    except Exception:
        return False

