        if isinstance(token_object, dict) and 'user_id' in token_object and 'timestamp' in token_object:
            return token_object
        else:
            return None
    except (base64.binascii.Error, json.JSONDecodeError, ValueError, TypeError):
        return None

from flask import Flask, request
import yaml
import io

app = Flask(__name__)

@app.route('/yaml', methods=['POST'])
def yaml_load():
    '''
    Get YAML data from request, parse it, and return it.
    '''
    try:
        if request.method == 'POST':
            yaml_data = request.data.decode('utf-8')
            try:
                parsed_yaml = yaml.safe_load(io.StringIO(yaml_data))
                return parsed_yaml, 200
            except yaml.YAMLError as e:
                return {'error': str(e)}, 400
        else:
            return {'error': 'Method not allowed'}, 405
    except Exception as e:
        return {'error': str(e)}, 500
